mapper.insert:
INSERT INTO SHOP_CART (
    BOOK_NUM
    , CART_CNT
    , MEM_EMAIL
) VALUES (
   #{bookNum}
    , #{cartCnt}
    , #{memEmail}
)

mapper.select:
SELECT MEM_EMAIL
FROM SHOP_CART
WHERE MEM_EMAIL = #{memEmail}
AND BOOK_NUM = #{bookNum}

mapper.update:
UPDATE SHOP_CART
SET
    CART_DATE = SYSDATE()
    , CART_CNT = CART_CNT + #{cartCnt}
WHERE MEM_EMAIL = #{memEmail}
AND BOOK_NUM = #{bookNum}

UPDATE SHOP_CART
SET
    CART_CNT = #{cartCnt}
WHERE CART_NUM = #{cartNum}
